1.1 加减乘除
用 C 验证基本算术运算。修改数值后重新运行单元格即可看到结果。
设 \(a = 7\), \(b = 3\)，计算四则运算：
#include &lt;stdio.h&gt;

int main() {
    int a = 7, b = 3;
    printf("a + b = %d\n", a + b);
    printf("a - b = %d\n", a - b);
    printf("a * b = %d\n", a * b);
    printf("a / b = %d\n", a / b);
    printf("a %% b = %d\n", a % b);
    return 0;
}

a + b = 10
a - b = 4
a * b = 21
a / b = 2
a % b = 1

1.2 浮点精度
比较 \(\frac{1}{3}\) 的单精度与双精度表示：

#include &lt;stdio.h&gt;

int main() {
    float f = 1.0f / 3.0f;
    double d = 1.0 / 3.0;
    printf("float:  %.9f\n", f);
    printf("double: %.15f\n", d);
    return 0;
}

float:  0.333333343
double: 0.333333333333333

1.3 勾股定理
验证 \(3^2 + 4^2 = 5^2\)，并计算斜边 \(c = \sqrt{a^2 + b^2}\)：

#include &lt;stdio.h&gt;
#include &lt;math.h&gt;

int main() {
    double a = 3.0, b = 4.0;
    double c = sqrt(a*a + b*b);
    printf("c = %.6f\n", c);
    return 0;
}

c = 5.000000
